terraform:
terraform {
  required_version = ">= 1.5"
}

locals {
  tags = {
    project     = "archmorph"
    environment = "prod"
    managed_by  = "archmorph"
  }
}

resource "azurerm_user_assigned_identity" "db" {
  name                = "id-gcp-data-secure"
  location            = "westeurope"
  resource_group_name = "rg-gcp-data-secure"
  tags                = local.tags
}

resource "azurerm_key_vault" "main" {
  name                          = "kvgcpdatasecure01"
  location                      = "westeurope"
  resource_group_name           = "rg-gcp-data-secure"
  tenant_id                     = "00000000-0000-0000-0000-000000000000"
  sku_name                      = "standard"
  public_network_access_enabled = false
  enable_rbac_authorization     = true
  tags                          = local.tags
}

resource "azurerm_postgresql_flexible_server" "main" {
  name                          = "pg-gcp-data-secure"
  resource_group_name           = "rg-gcp-data-secure"
  location                      = "westeurope"
  version                       = "14"
  delegated_subnet_id           = "/subscriptions/000/resourceGroups/rg/providers/Microsoft.Network/virtualNetworks/vnet/subnets/db"
  private_dns_zone_id           = "/subscriptions/000/resourceGroups/rg/providers/Microsoft.Network/privateDnsZones/privatelink.postgres.database.azure.com"
  public_network_access_enabled = false
  administrator_login           = "archmorphadmin"
  storage_mb                    = 32768
  sku_name                      = "B_Standard_B1ms"
  zone                          = "1"
  tags                          = local.tags
}

resource "azurerm_storage_account" "diag" {
  name                            = "stgcpdatadiag01"
  location                        = "westeurope"
  resource_group_name             = "rg-gcp-data-secure"
  account_tier                    = "Standard"
  account_replication_type        = "LRS"
  min_tls_version                 = "TLS1_2"
  public_network_access_enabled   = false
  infrastructure_encryption_enabled = true
  tags                            = local.tags
}

resource "azurerm_monitor_diagnostic_setting" "postgres" {
  name               = "diag-postgres"
  target_resource_id = azurerm_postgresql_flexible_server.main.id
  storage_account_id = azurerm_storage_account.diag.id

  enabled_log {
    category = "PostgreSQLLogs"
  }

  metric {
    category = "AllMetrics"
    enabled  = true
  }
}

bicep:
targetScope = 'subscription'

param location string = 'westeurope'

var tags = {
  project: 'archmorph'
  environment: 'prod'
  managedBy: 'archmorph'
}

resource identity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'id-gcp-data-secure'
  location: location
  tags: tags
}

resource keyVault 'Microsoft.KeyVault/vaults@2023-07-01' = {
  name: 'kv-gcp-data-secure'
  location: location
  properties: {
    tenantId: '00000000-0000-0000-0000-000000000000'
    sku: {
      family: 'A'
      name: 'standard'
    }
    enableRbacAuthorization: true
    publicNetworkAccess: 'Disabled'
  }
  tags: tags
}

resource postgres 'Microsoft.DBforPostgreSQL/flexibleServers@2023-06-01-preview' = {
  name: 'pg-gcp-data-secure'
  location: location
  properties: {
    version: '14'
    publicNetworkAccess: 'Disabled'
    administratorLogin: 'archmorphadmin'
    storage: {
      storageSizeGB: 32
    }
  }
  identity: {
    type: 'SystemAssigned'
  }
  tags: tags
}

resource diagnosticsStorage 'Microsoft.Storage/storageAccounts@2023-05-01' = {
  name: 'stgcpdatadiag01'
  location: location
  sku: {
    name: 'Standard_LRS'
  }
  kind: 'StorageV2'
  properties: {
    minimumTlsVersion: '1.2'
    publicNetworkAccess: 'Disabled'
  }
  tags: tags
}

resource postgresDiag 'Microsoft.Insights/diagnosticSettings@2021-05-01-preview' = {
  name: 'diag-postgres'
  scope: postgres
  properties: {
    storageAccountId: diagnosticsStorage.id
    logs: [
      {
        category: 'PostgreSQLLogs'
        enabled: true
      }
    ]
    metrics: [
      {
        category: 'AllMetrics'
        enabled: true
      }
    ]
  }
}
